+          ...state,
+          isSentencePracticeComplete: true,
+        };
+      }
+
+      return {
+        ...state,
+        currentQuestionIndex: state.currentQuestionIndex + 1,
+        questionStartTime: Date.now(),
+      };
+
+    case "PREVIOUS_QUESTION":
+      if (state.currentQuestionIndex === 0) {
+        return state;
+      }
+
+      return {
+        ...state,
+        currentQuestionIndex: state.currentQuestionIndex - 1,
+        questionStartTime: Date.now(),
+      };
+
+    case "FINISH_SENTENCE":
+      return {
+        ...state,
+        isSentencePracticeComplete: true,
+      };
+
+    case "RESTART_SENTENCE":
+      return {
+        currentQuestionIndex: 0,
+        userSentence: "",
+        showResult: false,
+        score: 0,
+        answeredQuestions: new Array(action.payload.questionCount).fill(false),
+        userAnswers: new Array(action.payload.questionCount).fill(""),
+        isSentencePracticeComplete: false,
+        showUserSentences: {},
+        questionStartTime: Date.now(),
+        restartKey: Date.now(),
+        isSubmitting: false,
+        feedbackByQuestion: {},
+        resultsByQuestion: {},
+      };
+
+    case "TOGGLE_USER_SENTENCES":
+      return {
+        ...state,
+        showUserSentences: {
+          ...state.showUserSentences,
+          [action.payload]: !state.showUserSentences[action.payload],
+        },
+      };
+
+    case "SET_QUESTION_START_TIME":
+      return {
+        ...state,
+        questionStartTime: action.payload,
+      };
+
+    case "LOAD_QUESTION_STATE":
+      return {
+        ...state,
+        userSentence: action.payload.userSentence,
+        showResult: action.payload.showResult,
+      };
+
+    default:
+      return state;
+  }
+}
+
+function normalizeText(value: string) {
+  return value.toLowerCase().replace(/[^a-z0-9\s]/g, " ").replace(/\s+/g, " ").trim();
+}
+
+function sentenceIncludesWord(sentence: string, word: string) {
+  const escapedWord = word.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
+  return new RegExp(`\\b${escapedWord}\\b`, "i").test(sentence);
+}
+
+function buildLocalSentenceFeedback(
+  sentence: string,
+  word: VocabularyWord
+): SentenceFeedback {
+  const words = normalizeText(sentence).split(" ").filter(Boolean);
+  const hasWord = sentenceIncludesWord(sentence, word.word);
+  const hasEnoughWords = words.length >= 5;
+  const startsWithCapital = /^[A-Z]/.test(sentence.trim());
+  const hasEndingPunctuation = /[.!?]$/.test(sentence.trim());
+  const correct = hasWord && hasEnoughWords;
+
+  let aiResponse = `Basic check: your sentence ${correct ? "uses" : "does not yet use"} "${word.word}" in a complete enough sentence.`;
+  let hint = `Use "${word.word}" to mean "${word.definition}" in an original sentence.`;
+
+  if (!hasWord) {
+    aiResponse = `Your sentence needs to include the word "${word.word}".`;
+    hint = `Try rewriting the sentence with "${word.word}" as the focus.`;
+  } else if (!hasEnoughWords) {
+    aiResponse =
+      "Your sentence includes the vocabulary word, but it is too short to show meaning clearly.";
+    hint = "Add context that proves you understand the word's meaning.";
+  } else if (!startsWithCapital || !hasEndingPunctuation) {
+    aiResponse =
+      "Your sentence uses the word, but check capitalization and ending punctuation.";
+    hint = "A polished sentence should start with a capital letter and end with punctuation.";
+  }
+
+  return {
+    correct,
+    exampleSentence: word.example,
+    aiResponse,
+    hint,
+    source: "local",
+  };
+}
+
+function calculateMasteryLevel(
+  correctAttempts: number,
+  totalAttempts: number,
+  consecutiveCorrect: number
+): WordPerformance["masteryLevel"] {
+  if (totalAttempts === 0) return "learning";
+
+  const accuracy = correctAttempts / totalAttempts;
+
+  if (accuracy >= 0.9 && consecutiveCorrect >= 3) return "mastered";
+  if (accuracy >= 0.7 && consecutiveCorrect >= 2) return "proficient";
+  if (accuracy >= 0.5) return "learning";
+  return "struggling";
+}
