+}
+
+export function addXPForCorrectAnswer(questionId: string, scoreBandRange = 1) {
+  const profile = getUserProfile();
+  const xpGain = scoreBandRange * 10;
+  const updatedProfile: UserProfileWithHistory = {
+    ...profile,
+    totalXP: profile.totalXP + xpGain,
+    questionsAnswered: profile.questionsAnswered + 1,
+    correctAnswers: profile.correctAnswers + 1,
+    answeredQuestionIds: profile.answeredQuestionIds.includes(questionId)
+      ? profile.answeredQuestionIds
+      : [...profile.answeredQuestionIds, questionId],
+  };
+  updatedProfile.level = calculateLevel(updatedProfile.totalXP);
+  return saveUserProfile(updatedProfile);
+}
+
+export function reduceXPForIncorrectAnswer(questionId: string, scoreBandRange = 1) {
+  const profile = getUserProfile();
+  const xpLoss = Math.max(0, scoreBandRange * 2);
