+    ...profile,
+    totalXP: Math.max(0, profile.totalXP - xpLoss),
+    questionsAnswered: profile.questionsAnswered + 1,
+    incorrectAnswers: profile.incorrectAnswers + 1,
+    answeredQuestionIds: profile.answeredQuestionIds.includes(questionId)
+      ? profile.answeredQuestionIds
+      : [...profile.answeredQuestionIds, questionId],
+  };
+  updatedProfile.level = calculateLevel(updatedProfile.totalXP);
+  return saveUserProfile(updatedProfile);
+}
