import { createOpenRouter } from "@openrouter/ai-sdk-provider";
import { generateObject } from "ai";
import { z } from "zod";

const feedbackSchema = z.object({
  correct: z.boolean(),
  exampleSentence: z.string().min(1),
  aiResponse: z.string().min(1),
  hint: z.string().min(1),
});

type ChatTask = "validate-user-definition" | "validate-user-sentence";

function jsonResponse(body: unknown, status: number) {
  return Response.json(body, { status });
}

function getString(value: unknown): string {
  return typeof value === "string" ? value.trim() : "";
}

function isSupportedTask(task: string): task is ChatTask {
  return task === "validate-user-definition" || task === "validate-user-sentence";
}

function buildPrompt(task: ChatTask, data: Record<string, unknown>, message: string) {
  const word = getString(data.word);
  const correctDefinition = getString(data.correctDefinition);
  const exampleSentence = getString(data.exampleSentence);

  if (task === "validate-user-definition") {
    const userDefinition = getString(data.userDefinition) || message;

    return {
      word,
      userInput: userDefinition,
      prompt: [
        `Vocabulary word: ${word}`,
        `Correct definition: ${correctDefinition}`,
        exampleSentence ? `Reference sentence: ${exampleSentence}` : "",
        `Learner definition: ${userDefinition}`,
        "",
        "Decide whether the learner definition captures the vocabulary word's meaning.",
        "Be encouraging and specific. Mark correct only when the meaning is substantially right, even if wording differs.",
      ]
        .filter(Boolean)
        .join("\n"),
    };
  }

  const userSentence = getString(data.userSentence) || message;

  return {
    word,
    userInput: userSentence,
    prompt: [
      `Vocabulary word: ${word}`,
      `Definition: ${correctDefinition}`,
      exampleSentence ? `Reference sentence: ${exampleSentence}` : "",
      `Learner sentence: ${userSentence}`,
      "",
      "Decide whether the learner wrote a complete original sentence that uses the vocabulary word naturally and with the intended meaning.",
      "Mark correct only when the sentence includes the word, is a real sentence, and uses the word in a way consistent with the definition.",
      "If incorrect, explain the issue briefly and give a useful hint.",
    ]
      .filter(Boolean)
      .join("\n"),
  };
}

export async function POST(req: Request) {
  let body: unknown;

  try {
    body = await req.json();
  } catch {
    return jsonResponse(
      { success: false, message: "Request body must be valid JSON." },
      400
    );
  }

  const requestBody = body && typeof body === "object" ? body : {};
  const task = getString((requestBody as { task?: unknown }).task);
  const message = getString((requestBody as { message?: unknown }).message);
  const dataValue = (requestBody as { data?: unknown }).data;
  const data =
    dataValue && typeof dataValue === "object"
      ? (dataValue as Record<string, unknown>)
      : {};

  if (!task) {
    return jsonResponse(
      {
        success: false,
        message:
          "Missing task. Use validate-user-definition or validate-user-sentence.",
      },
      400
    );
  }

  if (!isSupportedTask(task)) {
    return jsonResponse(
      {
        success: false,
        message: `Unsupported task "${task}". Use validate-user-definition or validate-user-sentence.`,
      },
      400
    );
  }

  const word = getString(data.word);
  const correctDefinition = getString(data.correctDefinition);
  const userInput =
    task === "validate-user-definition"
      ? getString(data.userDefinition) || message
      : getString(data.userSentence) || message;

  if (!word || !correctDefinition || !userInput) {
    return jsonResponse(
      {
        success: false,
        message:
          "Missing required data. Include word, correctDefinition, and the learner response.",
      },
      400
    );
  }

  if (!process.env.OPENROUTER_KEY) {
    return jsonResponse(
      {
        success: false,
        message: "AI feedback is unavailable because the provider key is not configured.",
      },
      503
    );
  }

  const openrouter = createOpenRouter({
    apiKey: process.env.OPENROUTER_KEY,
  });

  try {
    const { prompt } = buildPrompt(task, data, message);
    const result = await generateObject({
      model: openrouter(process.env.OPENROUTER_MODEL || "openai/gpt-4o-mini"),
      schema: feedbackSchema,
      mode: "json",
      temperature: 0.2,
      maxOutputTokens: 400,
      system:
        "You are a concise vocabulary tutor. Return only structured feedback in the requested schema.",
      prompt,
    });

    return jsonResponse({ success: true, result: result.object }, 200);
  } catch (error) {
    console.error("OpenRouter vocabulary feedback failed:", error);

    return jsonResponse(
      {
        success: false,
        message: "AI feedback could not be generated.",
      },
      502
    );
  }
}

