interface SentenceQuestion {
  word: VocabularyWord;
}

interface SentenceFeedback {
  correct: boolean;
  exampleSentence: string;
  aiResponse: string;
  hint: string;
  source: "ai" | "local";
}

interface VocabsFormASentencePracticeProps {
  onBackToPracticeSelection?: () => void;
}

interface SentenceState {
  currentQuestionIndex: number;
  userSentence: string;
  showResult: boolean;
  score: number;
  answeredQuestions: boolean[];
  userAnswers: string[];
  isSentencePracticeComplete: boolean;
  showUserSentences: { [key: number]: boolean };
  questionStartTime: number;
  restartKey: number;
  isSubmitting: boolean;
  feedbackByQuestion: { [key: number]: SentenceFeedback };
  resultsByQuestion: { [key: number]: boolean };
}

type SentenceAction =
  | { type: "INITIALIZE_SENTENCE"; payload: { questionCount: number } }
  | { type: "UPDATE_SENTENCE"; payload: string }
  | { type: "START_SUBMISSION" }
  | { type: "SUBMIT_SENTENCE"; payload: { feedback: SentenceFeedback } }
  | { type: "NEXT_QUESTION" }
  | { type: "PREVIOUS_QUESTION" }
  | { type: "FINISH_SENTENCE" }
  | { type: "RESTART_SENTENCE"; payload: { questionCount: number } }
  | { type: "TOGGLE_USER_SENTENCES"; payload: number }
  | { type: "SET_QUESTION_START_TIME"; payload: number }
  | {
      type: "LOAD_QUESTION_STATE";
      payload: { userSentence: string; showResult: boolean };
    };

const initialSentenceState: SentenceState = {
  currentQuestionIndex: 0,
  userSentence: "",
  showResult: false,
  score: 0,
  answeredQuestions: [],
  userAnswers: [],
  isSentencePracticeComplete: false,
  showUserSentences: {},
  questionStartTime: Date.now(),
  restartKey: 0,
  isSubmitting: false,
  feedbackByQuestion: {},
  resultsByQuestion: {},
};

function sentenceReducer(
  state: SentenceState,
  action: SentenceAction
): SentenceState {
  switch (action.type) {
    case "INITIALIZE_SENTENCE":
      return {
        ...state,
        answeredQuestions: new Array(action.payload.questionCount).fill(false),
        userAnswers: new Array(action.payload.questionCount).fill(""),
        questionStartTime: Date.now(),
        feedbackByQuestion: {},
        resultsByQuestion: {},
      };

    case "UPDATE_SENTENCE":
      return {
        ...state,
        userSentence: action.payload,
      };

    case "START_SUBMISSION":
      return {
        ...state,
        isSubmitting: true,
      };

    case "SUBMIT_SENTENCE": {
      const newAnsweredQuestions = [...state.answeredQuestions];
      const newUserAnswers = [...state.userAnswers];
      const newFeedbackByQuestion = { ...state.feedbackByQuestion };
      const newResultsByQuestion = { ...state.resultsByQuestion };
      const questionIndex = state.currentQuestionIndex;

      newAnsweredQuestions[questionIndex] = true;
      newUserAnswers[questionIndex] = state.userSentence.trim();
      newFeedbackByQuestion[questionIndex] = action.payload.feedback;
      newResultsByQuestion[questionIndex] = action.payload.feedback.correct;

      return {
        ...state,
        showResult: true,
        isSubmitting: false,
        score:
          !state.answeredQuestions[questionIndex] &&
          action.payload.feedback.correct
            ? state.score + 1
            : state.score,
        answeredQuestions: newAnsweredQuestions,
        userAnswers: newUserAnswers,
        feedbackByQuestion: newFeedbackByQuestion,
        resultsByQuestion: newResultsByQuestion,
      };
    }

    case "NEXT_QUESTION":
      if (state.currentQuestionIndex + 1 >= state.answeredQuestions.length) {
        return {
          ...state,
          isSentencePracticeComplete: true,
        };
      }

      return {
        ...state,
        currentQuestionIndex: state.currentQuestionIndex + 1,
        questionStartTime: Date.now(),
      };

    case "PREVIOUS_QUESTION":
      if (state.currentQuestionIndex === 0) {
        return state;
      }

      return {
        ...state,
        currentQuestionIndex: state.currentQuestionIndex - 1,
        questionStartTime: Date.now(),
      };

    case "FINISH_SENTENCE":
      return {
        ...state,
        isSentencePracticeComplete: true,
      };

    case "RESTART_SENTENCE":
      return {
        currentQuestionIndex: 0,
        userSentence: "",
        showResult: false,
        score: 0,
        answeredQuestions: new Array(action.payload.questionCount).fill(false),
        userAnswers: new Array(action.payload.questionCount).fill(""),
        isSentencePracticeComplete: false,
        showUserSentences: {},
        questionStartTime: Date.now(),
        restartKey: Date.now(),
        isSubmitting: false,
        feedbackByQuestion: {},
        resultsByQuestion: {},
      };

    case "TOGGLE_USER_SENTENCES":
      return {
        ...state,
        showUserSentences: {
          ...state.showUserSentences,
          [action.payload]: !state.showUserSentences[action.payload],
        },
      };

    case "SET_QUESTION_START_TIME":
      return {
        ...state,
        questionStartTime: action.payload,
      };

    case "LOAD_QUESTION_STATE":
      return {
        ...state,
        userSentence: action.payload.userSentence,
        showResult: action.payload.showResult,
      };

    default:
      return state;
  }
}

function normalizeText(value: string) {
  return value.toLowerCase().replace(/[^a-z0-9\s]/g, " ").replace(/\s+/g, " ").trim();
}

function sentenceIncludesWord(sentence: string, word: string) {
  const escapedWord = word.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  return new RegExp(`\\b${escapedWord}\\b`, "i").test(sentence);
}

function buildLocalSentenceFeedback(
  sentence: string,
  word: VocabularyWord
): SentenceFeedback {
  const words = normalizeText(sentence).split(" ").filter(Boolean);
  const hasWord = sentenceIncludesWord(sentence, word.word);
  const hasEnoughWords = words.length >= 5;
  const startsWithCapital = /^[A-Z]/.test(sentence.trim());
  const hasEndingPunctuation = /[.!?]$/.test(sentence.trim());
  const correct = hasWord && hasEnoughWords;

  let aiResponse = `Basic check: your sentence ${correct ? "uses" : "does not yet use"} "${word.word}" in a complete enough sentence.`;
  let hint = `Use "${word.word}" to mean "${word.definition}" in an original sentence.`;

  if (!hasWord) {
    aiResponse = `Your sentence needs to include the word "${word.word}".`;
    hint = `Try rewriting the sentence with "${word.word}" as the focus.`;
  } else if (!hasEnoughWords) {
    aiResponse =
